（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "d34b1d6c6554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097160", "c": "905", "s": "1001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "097", "exam_name": "097年專技高考律師、民間之公證人、會計師、社會工作師、不動產估價師、專利師考試暨地政士考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
